import { useState, useRef, useEffect } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";

const categories = [
  { key: "ngu-coc", label: "Ngũ Cốc", icon: "🌾" },
  { key: "banh-mi", label: "Bánh Mì", icon: "" },
  { key: "sua-trung", label: "Sữa & Trứng", icon: "🥛" },
  { key: "thit", label: "Thịt", icon: "🥩" },
  { key: "hai-san", label: "Hải Sản", icon: "🦐" },
  { key: "rau-cu", label: "Rau Củ", icon: "🥦" },
  { key: "trai-cay", label: "Trái Cây", icon: "🍎" },
];

const settingsItems = [
  { icon: "👤", label: "Tài khoản", key: "account" },
  { icon: "🔒", label: "Quyền riêng tư", key: "privacy" },
  { icon: "🖥️", label: "Màn hình", key: "display" },
  { icon: "♿", label: "Trợ năng", key: "accessibility" },
  { icon: "❓", label: "Trợ giúp", key: "help" },
];

function Menu() {
  const { cartCount } = useCart();
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [settingsOpen, setSettingsOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setSettingsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSettingClick = (key) => {
    setSettingsOpen(false);
    alert(`Tính năng "${settingsItems.find(i => i.key === key)?.label}" đang được phát triển.`);
  };

  const handleLogout = () => {
    setSettingsOpen(false);
    logout();
    navigate("/");
  };

  return (
    <header style={styles.header}>
      {/* Top bar */}
      <div style={styles.topBar}>
        <div style={styles.logo} onClick={() => navigate("/")}>
          <span style={styles.logoIcon}>🛒</span>
          <span style={styles.logoText}>FoodMart</span>
          <span style={styles.logoSub}>Siêu Thị Online</span>
        </div>

        <div style={styles.searchBar}>
          <input
            type="text"
            placeholder="Tìm kiếm thực phẩm..."
            style={styles.searchInput}
            onKeyDown={(e) => {
              if (e.key === "Enter") navigate("/products");
            }}
          />
          <button style={styles.searchBtn}>🔍</button>
        </div>

        <div style={styles.topRight}>
          {/* Cart */}
          <div style={styles.cartBtn} onClick={() => navigate("/cart")}>
            <span style={styles.cartIcon}>🛒</span>
            <div style={styles.cartInfo}>
              <span style={styles.cartLabel}>Giỏ hàng</span>
              <span style={styles.cartCount}>{cartCount} sản phẩm</span>
            </div>
            {cartCount > 0 && (
              <span style={styles.cartBadge}>{cartCount}</span>
            )}
          </div>

          {/* Auth area */}
          {user ? (
            /* Settings dropdown when logged in */
            <div style={styles.settingsWrapper} ref={dropdownRef}>
              <button
                style={styles.settingsBtn}
                onClick={() => setSettingsOpen((prev) => !prev)}
                title="Cài đặt"
              >
                <div style={styles.avatarCircle}>
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <div style={styles.userMeta}>
                  <span style={styles.userName}>{user.name}</span>
                  <span style={styles.userEmail}>{user.email}</span>
                </div>
                <span style={{
                  ...styles.chevron,
                  transform: settingsOpen ? "rotate(180deg)" : "rotate(0deg)",
                }}>▾</span>
              </button>

              {settingsOpen && (
                <div style={styles.dropdown}>
                  {/* User info header */}
                  <div style={styles.dropdownHeader}>
                    <div style={styles.dropdownAvatar}>
                      {user.name.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <p style={styles.dropdownName}>{user.name}</p>
                      <p style={styles.dropdownEmail}>{user.email}</p>
                    </div>
                  </div>

                  <div style={styles.dropdownDivider} />

                  {/* Settings items */}
                  <p style={styles.dropdownSection}>CÀI ĐẶT</p>
                  {settingsItems.map((item) => (
                    <button
                      key={item.key}
                      style={styles.dropdownItem}
                      onClick={() => handleSettingClick(item.key)}
                      onMouseEnter={(e) => e.currentTarget.style.backgroundColor = "#f0fff4"}
                      onMouseLeave={(e) => e.currentTarget.style.backgroundColor = "transparent"}
                    >
                      <span style={styles.dropdownItemIcon}>{item.icon}</span>
                      <span style={styles.dropdownItemLabel}>{item.label}</span>
                      <span style={styles.dropdownArrow}>›</span>
                    </button>
                  ))}

                  <div style={styles.dropdownDivider} />

                  {/* Logout */}
                  <button
                    style={styles.logoutItem}
                    onClick={handleLogout}
                    onMouseEnter={(e) => e.currentTarget.style.backgroundColor = "#fff5f5"}
                    onMouseLeave={(e) => e.currentTarget.style.backgroundColor = "transparent"}
                  >
                    <span style={styles.dropdownItemIcon}>🚪</span>
                    <span style={{ color: "#e53e3e", fontWeight: "600", fontSize: "14px" }}>Đăng xuất</span>
                  </button>
                </div>
              )}
            </div>
          ) : (
            /* Login button when not logged in */
            <button style={styles.loginBtn} onClick={() => navigate("/login")}>
              🔑 Đăng Nhập
            </button>
          )}
        </div>
      </div>

      {/* Nav bar */}
      <nav style={styles.navBar}>
        <NavLink
          to="/"
          style={({ isActive }) => ({
            ...styles.navLink,
            backgroundColor: isActive ? "#2d8a5e" : "transparent",
            borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
          })}
        >
          🏠 Trang Chủ
        </NavLink>
        <NavLink
          to="/products"
          style={({ isActive }) => ({
            ...styles.navLink,
            backgroundColor: isActive ? "#2d8a5e" : "transparent",
            borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
          })}
        >
          🏪 Tất Cả Sản Phẩm
        </NavLink>
        {categories.map((cat) => (
          <NavLink
            key={cat.key}
            to={`/category/${cat.key}`}
            style={({ isActive }) => ({
              ...styles.navLink,
              backgroundColor: isActive ? "#2d8a5e" : "transparent",
              borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
            })}
          >
            {cat.icon} {cat.label}
          </NavLink>
        ))}
      </nav>
    </header>
  );
}

const styles = {
  header: {
    backgroundColor: "#38a169",
    boxShadow: "0 2px 8px rgba(0,0,0,0.2)",
    position: "sticky",
    top: 0,
    zIndex: 1000,
  },
  topBar: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    padding: "12px 32px",
    gap: "16px",
    maxWidth: "1400px",
    margin: "0 auto",
  },
  logo: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer",
    flexShrink: 0,
  },
  logoIcon: { fontSize: "28px" },
  logoText: {
    color: "white",
    fontSize: "22px",
    fontWeight: "800",
    letterSpacing: "1px",
    fontFamily: "sans-serif",
  },
  logoSub: {
    color: "#c6f6d5",
    fontSize: "11px",
    fontFamily: "sans-serif",
    alignSelf: "flex-end",
    marginBottom: "2px",
  },
  searchBar: {
    display: "flex",
    flex: 1,
    maxWidth: "500px",
    borderRadius: "8px",
    overflow: "hidden",
    boxShadow: "0 1px 4px rgba(0,0,0,0.15)",
  },
  searchInput: {
    flex: 1,
    padding: "10px 16px",
    border: "none",
    fontSize: "14px",
    outline: "none",
    fontFamily: "sans-serif",
  },
  searchBtn: {
    backgroundColor: "#f6ad55",
    border: "none",
    padding: "10px 16px",
    cursor: "pointer",
    fontSize: "16px",
  },
  topRight: {
    display: "flex",
    alignItems: "center",
    gap: "12px",
    flexShrink: 0,
  },
  cartBtn: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    cursor: "pointer",
    backgroundColor: "rgba(255,255,255,0.15)",
    padding: "8px 16px",
    borderRadius: "8px",
    position: "relative",
    transition: "background 0.2s",
  },
  cartIcon: { fontSize: "24px" },
  cartInfo: {
    display: "flex",
    flexDirection: "column",
  },
  cartLabel: {
    color: "#c6f6d5",
    fontSize: "11px",
    fontFamily: "sans-serif",
  },
  cartCount: {
    color: "white",
    fontSize: "13px",
    fontWeight: "600",
    fontFamily: "sans-serif",
  },
  cartBadge: {
    position: "absolute",
    top: "-6px",
    right: "-6px",
    backgroundColor: "#fc8181",
    color: "white",
    borderRadius: "50%",
    width: "20px",
    height: "20px",
    fontSize: "11px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: "700",
    fontFamily: "sans-serif",
  },

  /* Login button */
  loginBtn: {
    backgroundColor: "white",
    color: "#38a169",
    border: "none",
    padding: "9px 18px",
    borderRadius: "8px",
    fontSize: "14px",
    fontWeight: "700",
    cursor: "pointer",
    fontFamily: "sans-serif",
    boxShadow: "0 2px 6px rgba(0,0,0,0.15)",
    transition: "opacity 0.2s",
  },

  /* Settings / User button */
  settingsWrapper: {
    position: "relative",
    fontFamily: "sans-serif",
  },
  settingsBtn: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    cursor: "pointer",
    backgroundColor: "rgba(255,255,255,0.15)",
    border: "none",
    padding: "7px 14px",
    borderRadius: "8px",
    transition: "background 0.2s",
  },
  avatarCircle: {
    width: "34px",
    height: "34px",
    borderRadius: "50%",
    backgroundColor: "#f6ad55",
    color: "white",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: "800",
    fontSize: "15px",
    flexShrink: 0,
    fontFamily: "sans-serif",
  },
  userMeta: {
    display: "flex",
    flexDirection: "column",
    alignItems: "flex-start",
  },
  userName: {
    color: "white",
    fontSize: "13px",
    fontWeight: "700",
    fontFamily: "sans-serif",
    lineHeight: 1.2,
  },
  userEmail: {
    color: "#c6f6d5",
    fontSize: "11px",
    fontFamily: "sans-serif",
    lineHeight: 1.2,
    maxWidth: "130px",
    overflow: "hidden",
    textOverflow: "ellipsis",
    whiteSpace: "nowrap",
  },
  chevron: {
    color: "white",
    fontSize: "14px",
    transition: "transform 0.2s",
    fontFamily: "sans-serif",
  },

  /* Dropdown */
  dropdown: {
    position: "absolute",
    top: "calc(100% + 10px)",
    right: 0,
    backgroundColor: "white",
    borderRadius: "14px",
    boxShadow: "0 8px 32px rgba(0,0,0,0.16)",
    minWidth: "240px",
    padding: "8px",
    zIndex: 2000,
    border: "1px solid #e2e8f0",
  },
  dropdownHeader: {
    display: "flex",
    alignItems: "center",
    gap: "12px",
    padding: "10px 12px 12px",
  },
  dropdownAvatar: {
    width: "42px",
    height: "42px",
    borderRadius: "50%",
    backgroundColor: "#38a169",
    color: "white",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: "800",
    fontSize: "18px",
    flexShrink: 0,
    fontFamily: "sans-serif",
  },
  dropdownName: {
    fontSize: "14px",
    fontWeight: "700",
    color: "#2d3748",
    margin: "0 0 2px",
    fontFamily: "sans-serif",
  },
  dropdownEmail: {
    fontSize: "12px",
    color: "#718096",
    margin: 0,
    fontFamily: "sans-serif",
  },
  dropdownDivider: {
    height: "1px",
    backgroundColor: "#e2e8f0",
    margin: "4px 0",
  },
  dropdownSection: {
    fontSize: "10px",
    fontWeight: "700",
    color: "#a0aec0",
    letterSpacing: "1px",
    padding: "6px 12px 2px",
    margin: 0,
    fontFamily: "sans-serif",
  },
  dropdownItem: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    width: "100%",
    padding: "9px 12px",
    border: "none",
    backgroundColor: "transparent",
    borderRadius: "8px",
    cursor: "pointer",
    textAlign: "left",
    transition: "background 0.15s",
    fontFamily: "sans-serif",
  },
  dropdownItemIcon: {
    fontSize: "17px",
    width: "24px",
    textAlign: "center",
    flexShrink: 0,
  },
  dropdownItemLabel: {
    flex: 1,
    fontSize: "14px",
    color: "#2d3748",
    fontWeight: "500",
    fontFamily: "sans-serif",
  },
  dropdownArrow: {
    color: "#a0aec0",
    fontSize: "16px",
    fontFamily: "sans-serif",
  },
  logoutItem: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    width: "100%",
    padding: "9px 12px",
    border: "none",
    backgroundColor: "transparent",
    borderRadius: "8px",
    cursor: "pointer",
    textAlign: "left",
    transition: "background 0.15s",
    fontFamily: "sans-serif",
  },
  navBar: {
    display: "flex",
    backgroundColor: "#2f855a",
    overflowX: "auto",
    padding: "0 32px",
  },
  navLink: {
    color: "white",
    textDecoration: "none",
    padding: "10px 14px",
    fontSize: "13px",
    fontWeight: "500",
    whiteSpace: "nowrap",
    fontFamily: "sans-serif",
    transition: "background 0.2s",
  },
};

export default Menu;
